import{_ as s,c as n,o as a,a4 as p}from"./chunks/framework.BmPFG-Ev.js";const d=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"knowledge-point/nginx.md","filePath":"knowledge-point/nginx.md","lastUpdated":1721121559000}'),e={name:"knowledge-point/nginx.md"},l=p(`<h2 id="nginx-命令" tabindex="-1">nginx 命令 <a class="header-anchor" href="#nginx-命令" aria-label="Permalink to &quot;nginx 命令&quot;">​</a></h2><ol><li>启动 ./nginx</li><li>停止 ./nginx -s stop 直接退出 ./nginx -s quit 跑完接口退出</li><li>重启 ./nginx -s reload</li><li>查看配置文件是否出错 ./nginx -t</li><li>查看版本 ./nginx -v</li><li>指定配置文件 ./nginx -c conf/nginx.conf</li></ol><h2 id="nginx-配置文件讲解" tabindex="-1">nginx 配置文件讲解 <a class="header-anchor" href="#nginx-配置文件讲解" aria-label="Permalink to &quot;nginx 配置文件讲解&quot;">​</a></h2><div class="language-conf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span></span></span>
<span class="line"><span>#user  nobody;</span></span>
<span class="line"><span>#启动的进程 根据cpu核心 4核</span></span>
<span class="line"><span>worker_processes 1;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>#error_log  logs/error.log;</span></span>
<span class="line"><span>#error_log  logs/error.log  notice;</span></span>
<span class="line"><span>#error_log  logs/error.log  info;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>#pid        logs/nginx.pid;</span></span>
<span class="line"><span>events {</span></span>
<span class="line"><span>    # 最大并发连接数 worker_processes * worker_connections 每秒处理的请求数</span></span>
<span class="line"><span>    worker_connections 1024;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span>http {</span></span>
<span class="line"><span>    # meme类型 文件类型 </span></span>
<span class="line"><span>    include mime.types;</span></span>
<span class="line"><span>    default_type application/octet-stream;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    #log_format  main  &#39;$remote_addr - $remote_user [$time_local] &quot;$request&quot; &#39;</span></span>
<span class="line"><span>    #                  &#39;$status $body_bytes_sent &quot;$http_referer&quot; &#39;</span></span>
<span class="line"><span>    #                  &#39;&quot;$http_user_agent&quot; &quot;$http_x_forwarded_for&quot;&#39;;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    #access_log  logs/access.log  main;</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    sendfile on; # nginx特性 处理静态大文件 分布加载 性能好</span></span>
<span class="line"><span>    #tcp_nopush     on;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    #keepalive_timeout  0;</span></span>
<span class="line"><span>    keepalive_timeout 65;   # 超时时间</span></span>
<span class="line"><span>    #压缩 html css js</span></span>
<span class="line"><span>    gzip  on;</span></span>
<span class="line"><span>    gzip_comp_level 5;#1-9 压缩的级别 取中</span></span>
<span class="line"><span>    gzip_types text/css text/javascript application/javascript text/plain text/html application/x-javascript application/x-httpd-php image/jpeg image/gif image/png;    #压缩类型 要压缩的文件</span></span>
<span class="line"><span>    #负载均衡 默认是轮询 </span></span>
<span class="line"><span>    #weight=3 权重</span></span>
<span class="line"><span>    #灾备技术 backup 备份服务器</span></span>
<span class="line"><span>    upstream aaa {  #这里的aaa替换ip</span></span>
<span class="line"><span>        server 127.0.0.1:9001 </span></span>
<span class="line"><span>        server 127.0.0.1:9002</span></span>
<span class="line"><span>        server 127.0.0.1:9003</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    #限速技术 限制一分钟接口多少个 limit为自定义变量  限制内存为10兆 每秒发送5个请求</span></span>
<span class="line"><span>    limit_req_zone $binary_remote_addr zone=limit:10m rate=5r/s</span></span>
<span class="line"><span>    #缓存技术           #路径绝对路径  #缓存的目录结构      #缓存名字  #缓存的大小  最大1g    #失效时间一小时没用到就删除</span></span>
<span class="line"><span>    proxy_cache_path C:/nginx_cache levels=1:2 keys_zone=cachename:10m max_size=1g inactive=60m;</span></span>
<span class="line"><span>    #http服务器管理</span></span>
<span class="line"><span>    server {</span></span>
<span class="line"><span>        listen 8090;    #端口 可以有多个</span></span>
<span class="line"><span>        server_name localhost; #域名</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        #charset koi8-r;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        #access_log  logs/host.access.log  main;</span></span>
<span class="line"><span>        location / {    # 代理 / 代理的路径 </span></span>
<span class="line"><span>            root html;  #html的跟目录</span></span>
<span class="line"><span>            index index.html index.htm; #文件</span></span>
<span class="line"><span>            try_files $uri $uri/ /index.html; #如果请求的资源不存在，则尝试回退到index.html</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>        #处理跨域</span></span>
<span class="line"><span>        location /api {         #限制的5 短时间可以10  nodelay没延迟  超过就503</span></span>
<span class="line"><span>            limit_req zone=limit burst=10 nodelay 或者 delay=10</span></span>
<span class="line"><span>            proxy_pass http://aaa</span></span>
<span class="line"><span>            #请求接口只需要 /api/list 就可以   代理转发的地址为   http://localhost:9090/api/list</span></span>
<span class="line"><span>            #如果需要去掉/api</span></span>
<span class="line"><span>            rewrite ^/api/(.*) /$1 break;</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>        #匹配图片 做防盗链 我的图片被盗  不能看 可以配置白名单 跟在localhost后就行</span></span>
<span class="line"><span>        location ~*.*\\.(jpg|jpeg|gif|png|bmp|ico)$ {</span></span>
<span class="line"><span>            proxy_cache cachename;</span></span>
<span class="line"><span>            proxy_cache_methods GET;</span></span>
<span class="line"><span>            proxy_cache_key $host$uri$is_args$args;</span></span>
<span class="line"><span>            proxy_cache_valid 200 304 5m;#200位置为状态码 缓存5分钟1d为一天</span></span>
<span class="line"><span>            proxy_cache_min_uses 2; #触发两次缓存</span></span>
<span class="line"><span></span></span>
<span class="line"><span>            root html/static;   定位到html/static</span></span>
<span class="line"><span>            valid_referers none blocked loaclhost;  除了localhost其他都不允许</span></span>
<span class="line"><span>            #none 允许referer为空</span></span>
<span class="line"><span>            # blocked 允许referer没有 </span></span>
<span class="line"><span>            #允许来源是loaclhost </span></span>
<span class="line"><span>            #$invalid_referer 根据上边条件 如果条件成立 $invalid_referer为空</span></span>
<span class="line"><span>            if ($invalid_referer) {</span></span>
<span class="line"><span>                return 403;</span></span>
<span class="line"><span>            }</span></span>
<span class="line"><span>         }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        #error_page  404              /404.html;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        # redirect server error pages to the static page /50x.html</span></span>
<span class="line"><span>        #   错误码 转到哪里</span></span>
<span class="line"><span>        error_page 500 502 503 504 /50x.html;</span></span>
<span class="line"><span>        location = /50x.html {</span></span>
<span class="line"><span>            root html;</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        # proxy the PHP scripts to Apache listening on 127.0.0.1:80</span></span>
<span class="line"><span>        #</span></span>
<span class="line"><span>        #location ~ \\.php$ {</span></span>
<span class="line"><span>        #    proxy_pass   http://127.0.0.1;</span></span>
<span class="line"><span>        #}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        # pass the PHP scripts to FastCGI server listening on 127.0.0.1:9000</span></span>
<span class="line"><span>        #</span></span>
<span class="line"><span>        #location ~ \\.php$ {</span></span>
<span class="line"><span>        #    root           html;</span></span>
<span class="line"><span>        #    fastcgi_pass   127.0.0.1:9000;</span></span>
<span class="line"><span>        #    fastcgi_index  index.php;</span></span>
<span class="line"><span>        #    fastcgi_param  SCRIPT_FILENAME  /scripts$fastcgi_script_name;</span></span>
<span class="line"><span>        #    include        fastcgi_params;</span></span>
<span class="line"><span>        #}</span></span>
<span class="line"><span>        # deny access to .htaccess files, if Apache&#39;s document root</span></span>
<span class="line"><span>        # concurs with nginx&#39;s one</span></span>
<span class="line"><span>        #</span></span>
<span class="line"><span>        #location ~ /\\.ht {</span></span>
<span class="line"><span>        #    deny  all;</span></span>
<span class="line"><span>        #}</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span>    # another virtual host using mix of IP-, name-, and port-based configuration</span></span>
<span class="line"><span>    #</span></span>
<span class="line"><span>    #server {</span></span>
<span class="line"><span>    #    listen       8000;</span></span>
<span class="line"><span>    #    listen       somename:8080;</span></span>
<span class="line"><span>    #    server_name  somename  alias  another.alias;</span></span>
<span class="line"><span>    #    location / {</span></span>
<span class="line"><span>    #        root   html;</span></span>
<span class="line"><span>    #        index  index.html index.htm;</span></span>
<span class="line"><span>    #    }</span></span>
<span class="line"><span>    #}</span></span>
<span class="line"><span>    # HTTPS server</span></span>
<span class="line"><span>    #       每个server都是独立的 配置的跨域图片等都需要在配置一次 https跟http都可以访问</span></span>
<span class="line"><span>     #配置https 下载openssl 配置环境变量</span></span>
<span class="line"><span>      #1. 先 生成私钥 在终端中输入 生成一个private.key文件</span></span>
<span class="line"><span>     #    openssl genpkey -algorithm RSA -out private.key -pkeyopt rsa_keygen_bits:2048</span></span>
<span class="line"><span>      #  2. 生成证书请求文件CSR</span></span>
<span class="line"><span>      #   openssl req -new -key private.key -out server.csr -subj &quot;/C=CN/ST=GD/L=SZ/O=IT/CN=www.localhost.com&quot;</span></span>
<span class="line"><span>    #    3. 通过csr生成证书</span></span>
<span class="line"><span>      #   openssl x509 -req -in server.csr -signkey private.key -out server.crt</span></span>
<span class="line"><span>        #密钥没用csr文件没用</span></span>
<span class="line"><span>    server {</span></span>
<span class="line"><span>        listen       443 ssl;</span></span>
<span class="line"><span>        server_name  localhost;</span></span>
<span class="line"><span>        ssl_certificate      cert.pem;  #更换路径</span></span>
<span class="line"><span>        ssl_certificate_key  cert.key;  #更换路径   就可以了</span></span>
<span class="line"><span>        ssl_session_cache    shared:SSL:1m;</span></span>
<span class="line"><span>        ssl_session_timeout  5m;</span></span>
<span class="line"><span>        ssl_ciphers  HIGH:!aNULL:!MD5;</span></span>
<span class="line"><span>        ssl_prefer_server_ciphers  on;</span></span>
<span class="line"><span>        location / {</span></span>
<span class="line"><span>            root   html;</span></span>
<span class="line"><span>            index  index.html index.htm;</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>    }  </span></span>
<span class="line"><span>}</span></span></code></pre></div>`,4),i=[l];function c(t,o,r,_,h,m){return a(),n("div",null,i)}const x=s(e,[["render",c]]);export{d as __pageData,x as default};
